def average_list(nums):
    if not nums:
        return 0.0
    return sum(nums) / len(nums)

def has_duplicates(lst):
    seen = set()
    for item in lst:
        if item in seen:
            return True
        seen.add(item)
    return False

def unique_words(s):
    if not s:
        return 0
    words = s.lower().split()
    return len(set(words))

def count_consonants(s):
    vowels = 'aeiou'
    count = 0
    for c in s.lower():
        if c.isalpha() and c not in vowels:
            count += 1
    return count

def remove_vowels(s):
    result = ''
    for c in s:
        if c.lower() not in 'aeiou':
            result += c
    return result

def longest_word(words):
    if not words:
        return ''
    longest = words[0]
    for w in words:
        if len(w) > len(longest):
            longest = w
    return longest

def is_power_of_two(n):
    if n <= 0:
        return False
    while n % 2 == 0:
        n //= 2
    return n == 1

def count_odd(nums):
    count = 0
    for n in nums:
        if n % 2 != 0:
            count += 1
    return count

